import{_ as e,o as d,c as a,a0 as n}from"./chunks/framework.DTwdCQre.js";const u=JSON.parse('{"title":"运行时包映射","description":"面向贡献者的 claude-code-Go 运行时行为包级别映射","frontmatter":{"title":"运行时包映射","description":"面向贡献者的 claude-code-Go 运行时行为包级别映射"},"headers":[],"relativePath":"zh/architecture/runtime-package-map.md","filePath":"zh/architecture/runtime-package-map.md","lastUpdated":1777632127000}'),r={name:"zh/architecture/runtime-package-map.md"};function s(o,t,c,i,l,p){return d(),a("div",null,[...t[0]||(t[0]=[n(`<h1 id="运行时包映射" tabindex="-1">运行时包映射 <a class="header-anchor" href="#运行时包映射" aria-label="Permalink to &quot;运行时包映射&quot;">​</a></h1><p>本页面将产品工作流映射到负责实现的 Go 包。在修改运行时行为之前请参考此页面，确保修复落在正确的层次上。</p><h2 id="运行时流程" tabindex="-1">运行时流程 <a class="header-anchor" href="#运行时流程" aria-label="Permalink to &quot;运行时流程&quot;">​</a></h2><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>cmd/go-code</span></span>
<span class="line"><span>  -&gt; 配置加载器</span></span>
<span class="line"><span>  -&gt; 提供者注册表</span></span>
<span class="line"><span>  -&gt; 工具注册表</span></span>
<span class="line"><span>  -&gt; 权限策略</span></span>
<span class="line"><span>  -&gt; Agent 循环</span></span>
<span class="line"><span>  -&gt; TUI 或 REPL</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div><h2 id="包所有权" tabindex="-1">包所有权 <a class="header-anchor" href="#包所有权" aria-label="Permalink to &quot;包所有权&quot;">​</a></h2><table tabindex="0"><thead><tr><th>包</th><th>职责</th><th>备注</th></tr></thead><tbody><tr><td><code>cmd/go-code</code></td><td>进程入口、命令行参数、初始化、运行时组装</td><td>在此保持编排逻辑；避免在 <code>main</code> 中嵌入业务逻辑</td></tr><tr><td><code>pkg/tui</code></td><td>默认的 Bubble Tea 交互式 UI</td><td>应将斜杠命令委托给共享的命令层</td></tr><tr><td><code>pkg/tty</code></td><td>传统的基于行的 REPL</td><td>在 TUI 达到功能完备之前，作为命令覆盖范围的参考</td></tr><tr><td><code>internal/agent</code></td><td>Agent 循环、历史记录、压缩、恢复、会话跟踪钩子</td><td>负责停止原因分发和工具结果反馈</td></tr><tr><td><code>internal/api</code></td><td>Anthropic 请求/响应类型、HTTP 客户端、SSE 解析、API 错误分类</td><td>尽可能将提供者中立的逻辑放在此包之外</td></tr><tr><td><code>internal/provider</code></td><td>提供者接口和提供者适配器</td><td>Anthropic 和 OpenAI 兼容的差异在此处理</td></tr><tr><td><code>internal/config</code></td><td>配置加载和默认值</td><td>应为诊断输出暴露配置来源细节</td></tr><tr><td><code>internal/tool</code></td><td>工具接口、注册表和内置工具注册</td><td>工具定义必须保持简洁且符合 schema 验证</td></tr><tr><td><code>internal/tool/builtin</code></td><td>内置本地工具，如 read、edit、bash、tree、diff、web fetch、todo、notebook</td><td>副作用必须由调用方进行权限控制</td></tr><tr><td><code>internal/permission</code></td><td>权限策略、规则、提示器、文件边界、Bash 语义检查</td><td>此包做决策；agent/工具层必须强制执行</td></tr><tr><td><code>internal/session</code></td><td>JSONL 会话持久化和跟踪行辅助函数</td><td>需要标准化的 schema 以支持回放和调试</td></tr><tr><td><code>internal/hooks</code></td><td>工具执行前后钩子</td><td>预钩子失败应阻止执行</td></tr><tr><td><code>internal/skills</code></td><td>用户定义的可复用提示/工作流</td><td>无效的技能文件不应导致启动失败</td></tr><tr><td><code>internal/tool/mcp</code></td><td>MCP 客户端、传输层和适配器</td><td>MCP 工具必须进入相同的注册表和权限流程</td></tr><tr><td><code>internal/lsp</code></td><td>LSP 客户端功能</td><td>可选功能；未配置服务器时应安全关闭</td></tr><tr><td><code>internal/update</code></td><td>版本检查与二进制更新</td><td>仅限用户触发的网络行为</td></tr><tr><td><code>internal/cost</code></td><td>Token 和成本跟踪辅助</td><td>提供者定价假设必须有文档记录</td></tr><tr><td><code>internal/telemetry</code></td><td>可选的本地遥测原语</td><td>在产品/隐私策略明确前保持禁用</td></tr></tbody></table><h2 id="贡献者规则" tabindex="-1">贡献者规则 <a class="header-anchor" href="#贡献者规则" aria-label="Permalink to &quot;贡献者规则&quot;">​</a></h2><ul><li>UI 包不应重复命令语义。</li><li>工具实现应执行本地验证，但权限批准应高于工具执行层。</li><li>提供者适配器应在错误到达 UI 代码之前将其规范化。</li><li>需要 socket、家目录写入或构建二进制文件的测试必须记录这些要求。</li><li>公开文档只能声明经过测试验证或在 <code>PARITY.md</code> 中列出的工作流。</li></ul><blockquote><p>英文版本: <a href="/claude-code-Go/architecture/runtime-package-map.html">Runtime Package Map</a></p></blockquote>`,9)])])}const m=e(r,[["render",s]]);export{u as __pageData,m as default};
